// Cycle detection in object graphs
const seen = new WeakSet();

function traverse(obj, depth = 0) {
  if (obj === null || typeof obj !== 'object') return;

  if (seen.has(obj)) {
    console.log('Cycle detected, avoiding infinite loop');
    return;
  }

  seen.add(obj);

  for (const key of Object.keys(obj)) {
    console.log('  '.repeat(depth) + key + ':', obj[key]);
    traverse(obj[key], depth + 1);
  }
}

// Create a circular reference
const graph = { name: 'parent', child: null };
graph.child = { name: 'child', parent: null };
graph.child.parent = graph; // Back-reference (creates cycle)

traverse(graph);
// Will not infinite loop — cycle detected via WeakSet

