// Set — STRONG references (can leak)
const strongSet = new Set();

(function() {
  const obj = { data: new Array(100000).fill('x') };
  strongSet.add(obj);
  // obj still in strongSet after IIFE ends
  // obj cannot be GC'd — memory held!
})();

// strongSet still contains obj — memory NOT freed
console.log(strongSet.size); // 1 (the object is still there!)

// WeakSet — WEAK references (no leak)
const weakSet = new WeakSet();

(function() {
  const obj = { data: new Array(100000).fill('x') };
  weakSet.add(obj);
  // After IIFE, obj reference is gone
  // WeakSet's weak reference doesn't prevent GC
  // obj will be GC'd — memory freed!
})();

// Cannot verify size — WeakSet has no size property
