// 1. Object deduplication in data processing
const seenObjects = new WeakSet();

function deduplicate(arr) {
  const result = [];
  for (const obj of arr) {
    if (obj !== null && typeof obj === 'object') {
      if (!seenObjects.has(obj)) {
        seenObjects.add(obj);
        result.push(obj);
      }
    } else {
      result.push(obj); // Primitives pass through
    }
  }
  return result;
}

const a = { id: 1 };
const b = { id: 2 };
const c = a; // Same reference

console.log(deduplicate([a, b, c])); // [{ id: 1 }, { id: 2 }]
// c is skipped — same reference as a

// 2. Object registry with auto-cleanup
const registry = new WeakSet();

class ManagedResource {
  constructor(name) {
    this.name = name;
    registry.add(this);
  }

  isManaged() {
    return registry.has(this);
  }
}

const res = new ManagedResource('db-connection');
console.log(res.isManaged()); // true
// When res is GC'd, registry auto-cleans

